import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  MagnifyingGlassIcon,
  FunnelIcon,
  EyeIcon,
  ClockIcon,
  CheckCircleIcon,
  ExclamationTriangleIcon,
  Bars3Icon,
  XMarkIcon,
  MapPinIcon,
  UserIcon,
  HomeIcon,
  PlusCircleIcon,
  ArrowRightOnRectangleIcon
} from '@heroicons/react/24/outline';

const ComplaintHistory = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');
  const [filterCategory, setFilterCategory] = useState('all');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user') || '{}'));
  const navigate = useNavigate();
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  useEffect(() => {
    fetchComplaints();
  }, []);

  const fetchComplaints = async () => {
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('You must be logged in to view complaints');
        setLoading(false);
        return;
      }

      const response = await fetch('http://localhost:5000/api/complaints/my', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      const data = await response.json();

      if (response.ok) {
        setComplaints(data.complaints || []);
      } else {
        setError(data.message || 'Failed to fetch complaints');
      }
    } catch (error) {
      console.error('Error fetching complaints:', error);
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const categories = ['all', 'Infrastructure', 'Sanitation', 'Water Supply', 'Electricity', 'Roads', 'Public Safety', 'Noise Pollution', 'Other'];
  const statuses = ['all', 'pending', 'in-progress', 'resolved', 'rejected', 'closed'];

  const filteredComplaints = complaints.filter(complaint => {
    const matchesSearch = complaint.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      complaint.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (complaint.complaintId && complaint.complaintId.toLowerCase().includes(searchTerm.toLowerCase()));
    const matchesCategory = filterCategory === 'all' || complaint.category === filterCategory;
    const matchesStatus = filterStatus === 'all' || complaint.status === filterStatus;

    return matchesSearch && matchesCategory && matchesStatus;
  });

  const getStatusBadge = (status) => {
    const statusConfig = {
      'pending': { color: 'bg-yellow-100 text-yellow-800', icon: ClockIcon },
      'in-progress': { color: 'bg-blue-100 text-blue-800', icon: EyeIcon },
      'resolved': { color: 'bg-green-100 text-green-800', icon: CheckCircleIcon },
      'rejected': { color: 'bg-red-100 text-red-800', icon: ExclamationTriangleIcon },
      'closed': { color: 'bg-gray-100 text-gray-800', icon: CheckCircleIcon }
    };

    const config = statusConfig[status] || statusConfig['pending'];
    const Icon = config.icon;

    return (
      <span className={`inline-flex items-center px-2 py-1 text-[10px] font-bold rounded-full ${config.color}`}>
        <Icon className="h-3 w-3 mr-1" />
        {status.replace('-', ' ')}
      </span>
    );
  };

  const getPriorityBadge = (priority) => {
    const priorityConfig = {
      'low': { color: 'bg-gray-100 text-gray-800' },
      'medium': { color: 'bg-yellow-100 text-yellow-800' },
      'high': { color: 'bg-red-100 text-red-800' }
    };

    const config = priorityConfig[priority] || priorityConfig['medium'];

    return (
      <span className={`inline-flex px-2 py-1 text-[10px] font-bold rounded-full ${config.color}`}>
        {priority}
      </span>
    );
  };

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden font-sans">
      {/* Mobile Sidebar Toggle */}
      <div className="lg:hidden fixed bottom-6 right-6 z-50">
        <button
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          className="p-4 bg-blue-600 text-white rounded-full shadow-2xl hover:bg-blue-700 transition-all active:scale-95"
        >
          {isMenuOpen ? <XMarkIcon className="h-6 w-6" /> : <Bars3Icon className="h-6 w-6" />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-72 bg-white/80 backdrop-blur-xl border-r border-blue-100/50 shadow-2xl shadow-blue-500/5 transform transition-all duration-500 ease-[cubic-bezier(0.23,1,0.32,1)] lg:relative lg:translate-x-0 ${isMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-full flex flex-col">
          {/* Logo Section */}
          <div className="p-8 border-b border-blue-50/50 bg-gradient-to-br from-blue-50/30 to-white/50">
            <Link to="/" className="flex items-center space-x-3 group relative">
              <div className="absolute -inset-2 bg-blue-100/20 rounded-2xl scale-75 opacity-0 group-hover:opacity-100 group-hover:scale-110 transition-all duration-500 blur-xl"></div>
              <div className="relative w-11 h-11 bg-gradient-to-tr from-blue-600 to-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-200 group-hover:shadow-blue-300 transition-all duration-500 group-hover:-rotate-6">
                <MapPinIcon className="h-6 w-6 text-white" />
              </div>
              <div className="relative text-left">
                <h1 className="text-xl font-bold text-gray-900 tracking-tight leading-none">
                  Urban<span className="text-blue-600 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600">Insights</span>
                </h1>
                <p className="text-xs font-medium text-blue-500 mt-1 opacity-80">Citizen Portal</p>
              </div>
            </Link>
          </div>

          {/* User Profile Section */}
          <div className="px-6 py-8">
            <div className="p-4 bg-gradient-to-br from-blue-50/50 to-indigo-50/50 rounded-[1.5rem] border border-blue-100/50 flex items-center space-x-4 hover:shadow-xl hover:shadow-blue-500/5 transition-all duration-300">
              <div className="relative w-12 h-12 bg-white rounded-full flex items-center justify-center border-2 border-blue-100 shadow-sm flex-shrink-0 transition-transform duration-500 group-hover:scale-110">
                <UserIcon className="h-6 w-6 text-blue-600" />
              </div>
              <div className="flex-1 min-w-0 text-left">
                <p className="text-sm font-semibold text-gray-900 truncate">{user?.name || 'Citizen User'}</p>
                <p className="text-[11px] font-medium text-blue-500/80 truncate">{user?.email || 'Authenticated'}</p>
              </div>
            </div>
          </div>

          {/* Navigation Links */}
          <nav className="flex-1 px-4 py-2 space-y-1.5 overflow-y-auto custom-scrollbar">
            <Link to="/dashboard" className="group flex items-center space-x-3 px-5 py-4 text-gray-500 hover:bg-blue-50 hover:text-blue-700 rounded-2xl font-semibold transition-all duration-300 hover:translate-x-1">
              <HomeIcon className="h-5 w-5 text-gray-400 group-hover:text-blue-600 transition-colors" />
              <span className="tracking-tight">Overview</span>
            </Link>
            <Link to="/complaint-history" className="group flex items-center space-x-3 px-5 py-4 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-blue-500/20 transition-all duration-300 hover:scale-[1.02] active:scale-95">
              <ClockIcon className="h-5 w-5 transition-transform group-hover:scale-110" />
              <span className="tracking-tight">Complaint History</span>
            </Link>
            <Link to="/submit-complaint" className="group flex items-center space-x-3 px-5 py-4 text-gray-500 hover:bg-blue-50 hover:text-blue-700 rounded-2xl font-semibold transition-all duration-300 hover:translate-x-1">
              <PlusCircleIcon className="h-5 w-5 text-gray-400 group-hover:text-blue-600 transition-colors" />
              <span className="tracking-tight">New Incident</span>
            </Link>
          </nav>

          {/* Sign Out Section */}
          <div className="p-6">
            <button onClick={handleLogout} className="w-full group flex items-center justify-center space-x-2 py-4 px-4 rounded-2xl text-[13px] font-semibold text-red-500 hover:text-white hover:bg-red-500 border border-red-100/50 transition-all duration-300 active:scale-95 shadow-lg shadow-red-500/5 bg-white/50 backdrop-blur-sm">
              <ArrowRightOnRectangleIcon className="h-5 w-5 transition-transform group-hover:-translate-x-1" />
              <span>Sign Out</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Overlay */}
      {isMenuOpen && (
        <div className="lg:hidden fixed inset-0 bg-gray-900/40 backdrop-blur-sm z-30 transition-opacity" onClick={() => setIsMenuOpen(false)}></div>
      )}

      {/* Main Content Area */}
      <main className="flex-1 h-full overflow-y-auto bg-gray-50">
        <div className="max-w-7xl mx-auto px-6 lg:px-10 py-12">
          {/* Header */}
          <header className="mb-12">
            <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">Activity Log</h1>
            <p className="text-gray-500 mt-2 font-medium">Monitoring and managing your community reports.</p>
          </header>

          {/* Loading State */}
          {loading && (
            <div className="flex items-center justify-center h-64">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
            </div>
          )}

          {/* Error State */}
          {error && (
            <div className="mb-6 bg-red-50 border border-red-200 rounded-md p-4">
              <div className="flex">
                <ExclamationTriangleIcon className="h-5 w-5 text-red-400" />
                <div className="ml-3">
                  <h3 className="text-sm font-medium text-red-800">Error</h3>
                  <p className="mt-1 text-sm text-red-700">{error}</p>
                </div>
              </div>
            </div>
          )}

          {/* Content */}
          {!loading && !error && (
            <div>
              {/* Stats */}
              <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-12">
                {[
                  { label: 'Total Reports', count: complaints.length, icon: ClockIcon, color: 'text-blue-600', bg: 'bg-blue-50' },
                  { label: 'Pending', count: complaints.filter(c => c.status === 'pending').length, icon: ExclamationTriangleIcon, color: 'text-yellow-600', bg: 'bg-yellow-50' },
                  { label: 'In Progress', count: complaints.filter(c => c.status === 'in-progress').length, icon: EyeIcon, color: 'text-blue-500', bg: 'bg-blue-50/50' },
                  { label: 'Resolved', count: complaints.filter(c => c.status === 'resolved').length, icon: CheckCircleIcon, color: 'text-emerald-600', bg: 'bg-emerald-50' }
                ].map((stat, i) => (
                  <div key={i} className="bg-white/80 backdrop-blur-xl p-6 rounded-[2rem] border border-blue-50/50 shadow-xl shadow-blue-500/5 hover:scale-[1.02] transition-transform duration-300">
                    <div className="flex items-center space-x-4">
                      <div className={`p-3 rounded-2xl ${stat.bg} ${stat.color}`}>
                        <stat.icon className="h-6 w-6" />
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-gray-400">{stat.label}</p>
                        <p className="text-2xl font-bold text-gray-900 tracking-tight">{stat.count}</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              {/* Filters */}
              <div className="bg-white/80 backdrop-blur-xl p-8 rounded-[2.5rem] border border-blue-50/50 shadow-2xl shadow-blue-500/5 mb-10">
                <div className="flex flex-col lg:flex-row lg:items-center gap-6">
                  <div className="flex-1 relative group">
                    <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                      <MagnifyingGlassIcon className="h-5 w-5 text-gray-300 group-focus-within:text-blue-500 transition-colors" />
                    </div>
                    <input
                      type="text"
                      className="block w-full pl-12 pr-4 py-4 bg-gray-50/50 border border-transparent rounded-2xl focus:bg-white focus:border-blue-500/30 focus:ring-4 focus:ring-blue-500/5 text-gray-900 font-bold placeholder-gray-300 transition-all outline-none"
                      placeholder="Search incident ID, title, or description..."
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>

                  <div className="flex flex-wrap gap-3">
                    <select
                      className="px-6 py-4 bg-gray-50/50 border border-transparent rounded-2xl text-gray-900 font-bold focus:bg-white focus:border-blue-500/30 outline-none transition-all cursor-pointer"
                      value={filterStatus}
                      onChange={(e) => setFilterStatus(e.target.value)}
                    >
                      {statuses.map(s => (
                        <option key={s} value={s}>{s === 'all' ? 'All Statuses' : s.replace('-', ' ').toUpperCase()}</option>
                      ))}
                    </select>

                    <select
                      className="px-6 py-4 bg-gray-50/50 border border-transparent rounded-2xl text-gray-900 font-bold focus:bg-white focus:border-blue-500/30 outline-none transition-all cursor-pointer"
                      value={filterCategory}
                      onChange={(e) => setFilterCategory(e.target.value)}
                    >
                      {categories.map(c => (
                        <option key={c} value={c}>{c === 'all' ? 'All Categories' : c.toUpperCase()}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>

              {/* Complaints List */}
              <div className="space-y-6">
                {filteredComplaints.length === 0 ? (
                  <div className="bg-white/50 backdrop-blur-sm p-12 text-center rounded-[2.5rem] border border-dashed border-gray-200">
                    <p className="text-gray-400 font-bold uppercase tracking-widest">No matching logs found</p>
                  </div>
                ) : (
                  filteredComplaints.map((complaint) => (
                    <div key={complaint._id} className="group bg-white/80 backdrop-blur-xl p-6 rounded-[2.5rem] border border-blue-50/50 shadow-xl shadow-blue-500/5 hover:shadow-blue-500/10 transition-all hover:scale-[1.01]">
                      <div className="flex flex-col lg:flex-row lg:items-start justify-between gap-6">
                        <div className="flex-1 space-y-4">
                          <div className="flex flex-wrap items-center gap-3">
                            <span className="px-3 py-1 bg-blue-50 text-blue-600 text-[10px] font-bold rounded-full">
                              {complaint.complaintId || `CMP-${complaint._id.slice(-6).toUpperCase()}`}
                            </span>
                            {getStatusBadge(complaint.status)}
                            {getPriorityBadge(complaint.priority)}
                          </div>

                          <div>
                            <h3 className="text-xl font-bold text-gray-900 tracking-tight group-hover:text-blue-600 transition-colors">{complaint.title}</h3>
                            <p className="text-gray-500 mt-2 font-medium leading-relaxed max-w-3xl">{complaint.description}</p>
                          </div>

                          <div className="flex flex-wrap items-center gap-6 text-[11px] font-bold text-gray-400">
                            <span className="flex items-center space-x-2">
                              <MapPinIcon className="h-4 w-4 text-blue-400" />
                              <span>{complaint.location?.address || 'Geolocation Recorded'}</span>
                            </span>
                            <span className="flex items-center space-x-2">
                              <PlusCircleIcon className="h-4 w-4 text-indigo-400" />
                              <span>{complaint.category}</span>
                            </span>
                            <span className="flex items-center space-x-2">
                              <ClockIcon className="h-4 w-4 text-gray-300" />
                              <span>{new Date(complaint.createdAt).toLocaleDateString()}</span>
                            </span>
                          </div>
                        </div>

                        <div className="flex flex-col sm:flex-row lg:flex-col gap-3 shrink-0">
